code = """import json

# Get agents who handled cases (from query 38)
agents_cases = locals()['var_functions.query_db:38']

# Get transfer history (from query 32)
transfer_history = locals()['var_functions.query_db:32']

# Extract agent IDs who handled cases
agent_ids = [agent['ownerid'] for agent in agents_cases]

# Convert to clean IDs (remove leading # if present)
clean_agent_ids = set()
for agent_id in agent_ids:
    clean_id = agent_id.lstrip('#')
    clean_agent_ids.add(clean_id)

# Count transfers for each agent
transfer_counts = {agent_id: 0 for agent_id in clean_agent_ids}

# Count transfers where agent was the source (oldvalue__c)
for transfer in transfer_history:
    old_value = transfer['oldvalue__c']
    # Only count actual transfers (not initial assignments which have oldvalue='None')
    if old_value and old_value != 'None':
        # Clean the ID (remove #)
        clean_old_value = old_value.lstrip('#')
        if clean_old_value in transfer_counts:
            transfer_counts[clean_old_value] += 1

# Print summary
print('__RESULT__:')
print("Agents: " + str(len(clean_agent_ids)))
print("Transfer records: " + str(len(transfer_history)))
print("Agents with transfers: " + str(len([c for c in transfer_counts.values() if c > 0])))

# Find agents with minimum transfer count (0 is the minimum)
min_transfers = min(transfer_counts.values())
agents_min_transfers = [agent_id for agent_id, count in transfer_counts.items() if count == min_transfers]

# For troubleshooting, show first few agents
agent_list = list(transfer_counts.items())[:10]
print("Sample transfer counts: " + str(agent_list))
print("Min transfer count: " + str(min_transfers))
print("Agents with min transfers: " + str(agents_min_transfers))"""

